// AUTO-GENERATED by Lovable Visual Editor. Do not edit by hand.
// Vite plugin that, when VITE_VISUAL_EDITOR=1, injects a tiny client-side
// script into index.html. The script forwards element clicks (carrying their
// data-vse source-location) to the parent window via postMessage so the
// Lovable editor iframe can show an inspector on the right element.
const CLIENT = `
(function(){
  if (window.__VSE_INSTALLED) return; window.__VSE_INSTALLED = true;
  var style = document.createElement('style');
  style.textContent = '[data-vse-hover]{outline:2px solid #3b82f680!important;outline-offset:2px!important;cursor:pointer}[data-vse-selected]{outline:2px solid #2563eb!important;outline-offset:2px!important}';
  document.head.appendChild(style);
  var lastHover = null;
  document.addEventListener('mouseover', function(e){
    var t = e.target && e.target.closest && e.target.closest('[data-vse]');
    if (lastHover && lastHover !== t) lastHover.removeAttribute('data-vse-hover');
    if (t) { t.setAttribute('data-vse-hover',''); lastHover = t; }
  }, true);
  document.addEventListener('mouseout', function(){
    if (lastHover) { lastHover.removeAttribute('data-vse-hover'); lastHover = null; }
  }, true);
  document.addEventListener('click', function(e){
    var t = e.target && e.target.closest && e.target.closest('[data-vse]');
    if (!t) return;
    e.preventDefault(); e.stopPropagation();
    parent.postMessage({ type:'vse:select', loc: t.getAttribute('data-vse'), tag: t.tagName.toLowerCase(), text: (t.textContent||'').trim().slice(0,80) }, '*');
  }, true);
  window.addEventListener('message', function(ev){
    if (!ev.data || ev.data.type !== 'vse:highlight') return;
    document.querySelectorAll('[data-vse-selected]').forEach(function(n){ n.removeAttribute('data-vse-selected'); });
    if (ev.data.loc) {
      var el = document.querySelector('[data-vse="' + ev.data.loc.replace(/"/g,'\\"') + '"]');
      if (el) { el.setAttribute('data-vse-selected',''); el.scrollIntoView({block:'center', behavior:'smooth'}); }
    }
  });
  parent.postMessage({ type:'vse:ready' }, '*');
})();
`;
module.exports = function visualEditorVitePlugin() {
  return {
    name: "visual-editor-client-injector",
    transformIndexHtml(html) {
      if (!process.env.VITE_VISUAL_EDITOR) return html;
      return html.replace("</body>", "<script>" + CLIENT + "</script></body>");
    },
  };
};
